#nullable enable // autogenerated

using MVZ2.Vanilla.Enemies;
using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using PVZEngine.Definitions;

namespace MVZ2.GameContent.Enemies
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.skeletonHorse_Animation)]
    public class SkeletonHorse_AnimationBehaviour : EnemyCommonAnimationBehaviour
    {
        public SkeletonHorse_AnimationBehaviour(string nsp, string name) : base(nsp, name)
        {
        }
        public override int GetAnimationState(int state)
        {
            switch (state)
            {
                case STATE_JUMP:
                    return ANIMATION_STATE_JUMP;
                case STATE_GALLOP:
                    return ANIMATION_STATE_GALLOP;
                case STATE_LAND:
                    return ANIMATION_STATE_LAND;
            }
            return base.GetAnimationState(state);
        }
        public const int STATE_GALLOP = VanillaEnemyStates.SKELETON_HORSE_GALLOP;
        public const int STATE_JUMP = VanillaEnemyStates.SKELETON_HORSE_JUMP;
        public const int STATE_LAND = VanillaEnemyStates.SKELETON_HORSE_LAND;
        public const int ANIMATION_STATE_JUMP = EnemyCommonAnimationBehaviour.ANIMATION_STATE_PRIVATE + 0;
        public const int ANIMATION_STATE_GALLOP = EnemyCommonAnimationBehaviour.ANIMATION_STATE_PRIVATE + 1;
        public const int ANIMATION_STATE_LAND = EnemyCommonAnimationBehaviour.ANIMATION_STATE_PRIVATE + 2;
    }
}
